"""
Player character physics and controls.
"""

import pygame

from core.constants import GRAVITY, MAX_FALL, JUMP_V, SPEED, COYOTE, JBUF
from ui.draw_helpers import draw_player


class Player:
    W, H = 26, 26

    def __init__(self, sx, sy):
        self._sx, self._sy = float(sx), float(sy)
        self.reset_pos()

    def reset_pos(self):
        self.x, self.y = self._sx, self._sy
        self.vx = self.vy = 0.0
        self.on_ground = False
        self.coyote    = 0.0
        self.jbuf      = 0.0
        self.alive     = True
        self.jumped    = False  # Flag to track if player just jumped

    def handle_input(self, keys):
        left  = keys[pygame.K_LEFT]  or keys[pygame.K_a]
        right = keys[pygame.K_RIGHT] or keys[pygame.K_d]
        jump  = keys[pygame.K_UP] or keys[pygame.K_w] or keys[pygame.K_SPACE]
        self.vx = SPEED * (right - left)
        if jump:
            self.jbuf = JBUF

    def update(self, dt, platforms, custom_jump_v=None):
        self.jumped = False  # Reset jump flag at start of frame
        self.vy = min(self.vy + GRAVITY*dt, MAX_FALL)
        self.coyote = max(0, self.coyote - dt)
        self.jbuf   = max(0, self.jbuf   - dt)

        if self.jbuf > 0 and (self.on_ground or self.coyote > 0):
            # Use custom jump velocity if provided (for boost tiles), otherwise use default
            jump_velocity = custom_jump_v if custom_jump_v is not None else JUMP_V
            self.vy = jump_velocity
            self.jumped = True  # Set flag when jump happens
            self.coyote = self.jbuf = 0

        self.on_ground = False
        self.x += self.vx * dt
        self._cx(platforms)
        self.y += self.vy * dt
        self._cy(platforms)

    def _cx(self, plats):
        r = self.rect
        for p in plats:
            if r.colliderect(p):
                if self.vx > 0:
                    self.x = p.left - self.W//2
                elif self.vx < 0:
                    self.x = p.right + self.W//2
                else:
                    # If platform motion causes overlap while idle, push to nearest side.
                    if r.centerx < p.centerx:
                        self.x = p.left - self.W//2
                    else:
                        self.x = p.right + self.W//2
                self.vx = 0
                r = self.rect

    def _cy(self, plats):
        r = self.rect
        for p in plats:
            if r.colliderect(p):
                if self.vy >= 0:
                    self.y = p.top
                    self.on_ground = True
                    self.coyote = COYOTE
                else:
                    self.y = p.bottom + self.H
                self.vy = 0
                r = self.rect

    @property
    def rect(self):
        return pygame.Rect(int(self.x - self.W//2), int(self.y - self.H),
                           self.W, self.H)

    def draw(self, surf, ox, oy):
        draw_player(surf, int(self.x)+ox, int(self.y)+oy, self.W, self.H)

"""
Player character physics and controls.
"""

import pygame

from core.constants import GRAVITY, MAX_FALL, JUMP_V, SPEED, COYOTE, JBUF
from ui.draw_helpers import draw_player


class Player:
    W, H = 26, 26

    def __init__(self, sx, sy):
        self._sx, self._sy = float(sx), float(sy)
        self.reset_pos()

    def reset_pos(self):
        self.x, self.y = self._sx, self._sy
        self.vx = self.vy = 0.0
        self.on_ground = False
        self.coyote    = 0.0
        self.jbuf      = 0.0
        self.alive     = True
        self.jumped    = False  # Flag to track if player just jumped

    def handle_input(self, keys):
        left  = keys[pygame.K_LEFT]  or keys[pygame.K_a]
        right = keys[pygame.K_RIGHT] or keys[pygame.K_d]
        jump  = keys[pygame.K_UP] or keys[pygame.K_w] or keys[pygame.K_SPACE]
        self.vx = SPEED * (right - left)
        if jump:
            self.jbuf = JBUF

    def update(self, dt, platforms, custom_jump_v=None, max_fall=None):
        self.jumped = False  # Reset jump flag at start of frame
        # Use provided max_fall or fall back to global constant
        fall_limit = max_fall if max_fall is not None else MAX_FALL
        self.vy = min(self.vy + GRAVITY*dt, fall_limit)
        self.coyote = max(0, self.coyote - dt)
        self.jbuf   = max(0, self.jbuf   - dt)

        if self.jbuf > 0 and (self.on_ground or self.coyote > 0):
            # Use custom jump velocity if provided (for boost tiles), otherwise use default
            jump_velocity = custom_jump_v if custom_jump_v is not None else JUMP_V
            self.vy = jump_velocity
            self.jumped = True  # Set flag when jump happens
            self.coyote = self.jbuf = 0

        self.on_ground = False
        self.x += self.vx * dt
        self._cx(platforms)
        self.y += self.vy * dt
        self._cy(platforms)

    def _cx(self, plats):
        r = self.rect
        for p in plats:
            if r.colliderect(p):
                if self.vx > 0:
                    self.x = p.left - self.W//2
                elif self.vx < 0:
                    self.x = p.right + self.W//2
                else:
                    # If platform motion causes overlap while idle, push to nearest side.
                    if r.centerx < p.centerx:
                        self.x = p.left - self.W//2
                    else:
                        self.x = p.right + self.W//2
                self.vx = 0
                r = self.rect

    def _cy(self, plats):
        r = self.rect
        for p in plats:
            if r.colliderect(p):
                if self.vy >= 0:
                    self.y = p.top
                    self.on_ground = True
                    self.coyote = COYOTE
                else:
                    self.y = p.bottom + self.H
                self.vy = 0
                r = self.rect

    @property
    def rect(self):
        return pygame.Rect(int(self.x - self.W//2), int(self.y - self.H),
                           self.W, self.H)

    def draw(self, surf, ox, oy):
        draw_player(surf, int(self.x)+ox, int(self.y)+oy, self.W, self.H)

"""
Spike obstacles (static or pop-up).
"""

import pygame

from engine.tl_runner import TLRunner
from ui.draw_helpers import (
    draw_spike, draw_spike_colored,
    draw_spike_down, draw_spike_down_colored,
    draw_spike_left, draw_spike_left_colored,
    draw_spike_right, draw_spike_right_colored
)


class SpikeObj:
    def __init__(self, x, y, w=32, h=14, steps=None, sensor=None, dir='up'):
        # x,y is the top-left corner (Tiled coords)
        # The spike tip is at (x + w//2, y)  i.e. centre-x, top-y
        # dir: 'up' (default), 'down', 'left', 'right'
        self.ox, self.oy = float(x), float(y)
        self.w = w
        self.h = h
        self.dir = dir
        self.sensor = sensor
        steps = steps or []
        self.runner = TLRunner(x, y, steps, loop=False)
        self.static = (sensor is None and not steps)
        if self.static:
            self.runner.active = True

    def reset(self):
        self.runner.reset()
        if self.static:
            self.runner.active = True
        if self.sensor:
            self.sensor.reset()

    def update(self, dt, prect):
        if self.sensor and not self.runner.active:
            if self.sensor.check(prect):
                self.runner.activate()
        self.runner.update(dt)

    @property
    def cx(self):
        return self.runner.x + self.w // 2

    @property
    def cy(self):
        return self.runner.y   # top of spike (tip)

    def _triggered(self):
        """True once the spike has been activated (or is always-on static)."""
        if self.static:
            return True
        if not (self.runner.active or self.runner.done):
            return False
        # If still waiting for the first step's delay, keep the spike hidden
        if self.runner.active and not self.runner.done and self.runner.step == 0:
            delay = self.runner.steps[0].get('d', 0.0) if self.runner.steps else 0.0
            if self.runner.timer < delay:
                return False
        return True

    def kill_rect(self):
        if not self._triggered():
            return pygame.Rect(0, 0, 0, 0)   # hidden – not yet dangerous

        # Adjust collision rect based on spike direction
        if self.dir == 'up':
            # Upward spike: collision is centered horizontally, extends upward
            return pygame.Rect(int(self.runner.x) + 2, int(self.runner.y), self.w - 4, self.h)
        elif self.dir == 'down':
            # Downward spike: collision extends downward
            return pygame.Rect(int(self.runner.x) + 2, int(self.runner.y), self.w - 4, self.h)
        elif self.dir == 'left':
            # Left spike: collision extends leftward
            return pygame.Rect(int(self.runner.x), int(self.runner.y) + 2, self.w, self.h - 4)
        elif self.dir == 'right':
            # Right spike: collision extends rightward
            return pygame.Rect(int(self.runner.x), int(self.runner.y) + 2, self.w, self.h - 4)
        else:
            # Default fallback
            return pygame.Rect(int(self.runner.x) + 2, int(self.runner.y), self.w - 4, self.h)

    def draw(self, surf, ox, oy, palette=None):
        if not self._triggered():
            return   # still hidden inside the floor tile – don't paint it
        cx, cy = int(self.cx) + ox, int(self.cy) + oy
        color = palette['spike'] if palette else (180, 180, 180)
        if self.dir == 'up':
            if palette is None:
                draw_spike(surf, cx, cy + 16)
            else:
                draw_spike_colored(surf, cx, cy + 16, color)
        elif self.dir == 'down':
            if palette is None:
                draw_spike_down(surf, cx, cy - self.h + 16)
            else:
                draw_spike_down_colored(surf, cx, cy - self.h + 16, color)
        elif self.dir == 'left':
            if palette is None:
                draw_spike_left(surf, cx + 16, cy)
            else:
                draw_spike_left_colored(surf, cx + 16, cy, color)
        elif self.dir == 'right':
            if palette is None:
                draw_spike_right(surf, cx - self.w + 16, cy)
            else:
                draw_spike_right_colored(surf, cx - self.w + 16, cy, color)

"""
Spike obstacles (static or pop-up).
"""

import pygame

from engine.tl_runner import TLRunner
from ui.draw_helpers import (
    draw_spike, draw_spike_colored,
    draw_spike_down, draw_spike_down_colored,
    draw_spike_left, draw_spike_left_colored,
    draw_spike_right, draw_spike_right_colored
)


class SpikeObj:
    def __init__(self, x, y, w=32, h=14, steps=None, sensor=None, dir='up'):
        # x,y is the top-left corner (Tiled coords)
        # The spike tip is at (x + w//2, y)  i.e. centre-x, top-y
        # dir: 'up' (default), 'down', 'left', 'right'
        self.ox, self.oy = float(x), float(y)
        self.w = w
        self.h = h
        self.dir = dir
        self.sensor = sensor
        steps = steps or []
        self.runner = TLRunner(x, y, steps, loop=False)
        self.static = (sensor is None and not steps)
        if self.static:
            self.runner.active = True

    def reset(self):
        self.runner.reset()
        if self.static:
            self.runner.active = True
        if self.sensor:
            self.sensor.reset()

    def update(self, dt, prect):
        if self.sensor and not self.runner.active:
            if self.sensor.check(prect):
                self.runner.activate()
        self.runner.update(dt)

    @property
    def cx(self):
        return self.runner.x + self.w // 2

    @property
    def cy(self):
        return self.runner.y   # top of spike (tip)

    def _triggered(self):
        """True once the spike has been activated (or is always-on static)."""
        if self.static:
            return True
        if not (self.runner.active or self.runner.done):
            return False
        # If still waiting for the first step's delay, keep the spike hidden
        if self.runner.active and not self.runner.done and self.runner.step == 0:
            delay = self.runner.steps[0].get('d', 0.0) if self.runner.steps else 0.0
            if self.runner.timer < delay:
                return False
        return True

    def kill_rect(self):
        if not self._triggered():
            return pygame.Rect(0, 0, 0, 0)   # hidden – not yet dangerous

        # Collision box should be much smaller than the tile
        # and match the actual visual spike size

        x = int(self.runner.x)
        y = int(self.runner.y)

        if self.dir == 'up':
            # Upward spike: small collision at the tip
            # Centered horizontally, extends upward
            return pygame.Rect(x + 10, y, 12, self.h + 4)
        elif self.dir == 'down':
            # Downward spike: small collision at the tip
            # Centered horizontally, extends downward
            return pygame.Rect(x + 10, y, 12, self.h + 4)
        elif self.dir == 'left':
            # Left spike: collision extends leftward
            # Scaled to actual spike visual size (~10 pixels)
            return pygame.Rect(x, y + 8, 16, 16)
        elif self.dir == 'right':
            # Right spike: collision extends rightward
            # Scaled to actual spike visual size (~10 pixels)
            return pygame.Rect(x + 16, y + 8, 16, 16)
        else:
            # Default fallback
            return pygame.Rect(x + 10, y, 12, self.h + 4)

    def draw(self, surf, ox, oy, palette=None):
        if not self._triggered():
            return   # still hidden inside the floor tile – don't paint it
        cx, cy = int(self.cx) + ox, int(self.cy) + oy
        color = palette['spike'] if palette else (180, 180, 180)
        if self.dir == 'up':
            if palette is None:
                draw_spike(surf, cx, cy + 16)
            else:
                draw_spike_colored(surf, cx, cy + 16, color)
        elif self.dir == 'down':
            if palette is None:
                draw_spike_down(surf, cx, cy - self.h + 16)
            else:
                draw_spike_down_colored(surf, cx, cy - self.h + 16, color)
        elif self.dir == 'left':
            if palette is None:
                draw_spike_left(surf, cx + 16, cy)
            else:
                draw_spike_left_colored(surf, cx + 16, cy, color)
        elif self.dir == 'right':
            if palette is None:
                draw_spike_right(surf, cx - self.w + 16, cy)
            else:
                draw_spike_right_colored(surf, cx - self.w + 16, cy, color)
